package com.example.demo.services;
import com.example.demo.dto.ProductoDTO;import com.example.demo.models.*;import com.example.demo.repository.VentaRepository;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.math.BigDecimal;import java.time.*;import java.time.format.TextStyle;import java.util.*;
@Service public class ReporteService{private final VentaRepository ventas;private final ProductoService productos;public ReporteService(VentaRepository ventas,ProductoService productos){this.ventas=ventas;this.productos=productos;}
@Transactional(readOnly=true)public Resumen resumen(){return resumen(LocalDate.now().withDayOfMonth(1),LocalDate.now());}@Transactional(readOnly=true)public Resumen resumen(LocalDate desde,LocalDate hasta){if(desde==null||hasta==null||desde.isAfter(hasta))throw new IllegalArgumentException("El rango de fechas es inválido");List<Venta>validas=ventas.confirmadasEntre(desde.atStartOfDay(),hasta.plusDays(1).atStartOfDay());LocalDate hoy=LocalDate.now();BigDecimal ventasHoy=validas.stream().filter(v->hoy.equals(v.getFecha().toLocalDate())).map(Venta::getTotal).reduce(BigDecimal.ZERO,BigDecimal::add),ingresos=validas.stream().map(Venta::getTotal).reduce(BigDecimal.ZERO,BigDecimal::add);List<ProductoDTO>ps=productos.listar();BigDecimal inventario=ps.stream().map(p->p.costo().multiply(BigDecimal.valueOf(p.stock()))).reduce(BigDecimal.ZERO,BigDecimal::add),ganancia=validas.stream().flatMap(v->v.getItems().stream()).map(i->i.getPrecioUnitario().subtract(i.getCostoUnitario()).multiply(cantidad(i))).reduce(BigDecimal.ZERO,BigDecimal::add);Map<String,Acumulado>ranking=new HashMap<>();validas.forEach(v->v.getItems().forEach(i->{String nombre=i.getProducto().getNombre(),unidad=i.getUnidadVenta()==Producto.UnidadVenta.PESO?"kg":"unidades";ranking.computeIfAbsent(nombre,k->new Acumulado(unidad)).cantidad=ranking.get(nombre).cantidad.add(cantidad(i));}));List<Ranking>top=ranking.entrySet().stream().sorted((a,b)->b.getValue().cantidad.compareTo(a.getValue().cantidad)).limit(8).map(e->new Ranking(e.getKey(),e.getValue().cantidad,e.getValue().unidad)).toList();Map<DayOfWeek,Long>porDia=new EnumMap<>(DayOfWeek.class);Map<Integer,Long>porHora=new TreeMap<>();Map<Venta.MedioPago,Long>porPago=new EnumMap<>(Venta.MedioPago.class);validas.forEach(v->{porDia.merge(v.getFecha().getDayOfWeek(),1L,Long::sum);porHora.merge(v.getFecha().getHour(),1L,Long::sum);porPago.merge(v.getMedioPago(),1L,Long::sum);});List<Metrica>dias=Arrays.stream(DayOfWeek.values()).map(d->new Metrica(d.getDisplayName(TextStyle.FULL,new Locale("es","AR")),BigDecimal.valueOf(porDia.getOrDefault(d,0L)))).toList(),horas=porHora.entrySet().stream().map(e->new Metrica(String.format("%02d:00",e.getKey()),BigDecimal.valueOf(e.getValue()))).toList(),pagos=porPago.entrySet().stream().sorted(Map.Entry.<Venta.MedioPago,Long>comparingByValue().reversed()).map(e->new Metrica(e.getKey().name().replace('_',' '),BigDecimal.valueOf(e.getValue()))).toList();return new Resumen(ventasHoy,ingresos,ganancia,inventario,ps.stream().filter(p->p.stock()<=p.stockMinimo()).count(),validas.size(),top,dias,horas,pagos);}
private BigDecimal cantidad(ItemVenta i){return i.getUnidadVenta()==Producto.UnidadVenta.PESO?BigDecimal.valueOf(i.getCantidad()).movePointLeft(3):BigDecimal.valueOf(i.getCantidad());}public record Resumen(BigDecimal ventasHoy,BigDecimal ingresosTotales,BigDecimal gananciaEstimada,BigDecimal inventarioValorizado,long stockBajo,long cantidadVentas,List<Ranking>masVendidos,List<Metrica>ventasPorDia,List<Metrica>ventasPorHora,List<Metrica>mediosPago){}public record Ranking(String producto,BigDecimal cantidad,String unidad){}public record Metrica(String etiqueta,BigDecimal valor){}private static class Acumulado{private BigDecimal cantidad=BigDecimal.ZERO;private final String unidad;private Acumulado(String unidad){this.unidad=unidad;}}
@Transactional(readOnly=true)public String exportarVentasCsv(){return exportarVentasCsv(LocalDate.of(2000,1,1),LocalDate.now());}@Transactional(readOnly=true)public String exportarVentasCsv(LocalDate desde,LocalDate hasta){StringBuilder csv=new StringBuilder("comprobante,fecha,estado,medio_pago,total,cliente\n");ventas.confirmadasEntre(desde.atStartOfDay(),hasta.plusDays(1).atStartOfDay()).forEach(v->{String cliente=v.getCliente()==null?"Consumidor final":v.getCliente().getNombre()+" "+v.getCliente().getApellido();csv.append(value(v.getNumeroComprobante())).append(',').append(v.getFecha()).append(',').append(v.getEstado()).append(',').append(v.getMedioPago()).append(',').append(v.getTotal()).append(',').append(value(cliente)).append('\n');});return csv.toString();}private String value(String value){if(value==null)return"";return'"'+value.replace("\"","\"\"")+'"';}}
